-- 6. Ashford Borough × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'ashford-borough',
  'Social media across Ashford Borough operates in distinct ecosystems that mirror the borough''s geographic and cultural diversity. Ashford town''s new-build estates have thriving Facebook community groups where residents ask for trade recommendations daily. Tenterden''s independent shopping culture drives a visually rich Instagram community. Rural villages rely on local Facebook pages and community noticeboards for service discovery. A social media presence set up without understanding these different ecosystems misses the audiences that generate your business. We build and optimise social media profiles for Ashford Borough businesses based on where your specific customers actually discover, vet, and recommend local businesses, whether that is a Chilmington Green Facebook group, Tenterden''s Instagram community, or a village parish noticeboard page.',
  'Ashford Borough''s social media landscape splits along geographic lines. The new-build estates at Chilmington Green, Finberry, and Park Farm have extremely active Facebook community groups with thousands of members posting daily recommendation requests. Tenterden''s social media presence is Instagram-heavy, reflecting the town''s visual appeal, independent boutiques, and food scene. The Kent and East Sussex Railway heritage attraction has its own significant social following that Tenterden businesses can leverage. Rural villages across the Weald maintain Facebook community pages that function as digital noticeboards. The commuter population is active on LinkedIn, creating B2B opportunities for professional services at International House and the Commercial Quarter.',
  'Social media adoption varies dramatically across Ashford Borough. Tenterden''s independent businesses generally maintain stronger social presence, driven by the tourism economy and the visual nature of their offerings. Ashford town centre businesses are inconsistent, with some investing in social media while many remain dormant. New estate community groups have created a powerful recommendation channel that businesses can access only with properly set up profiles. Rural businesses are almost entirely absent from social media.',
  'We set up social media for Ashford Borough businesses based on the specific ecosystem where their customers engage. Trades targeting the new estates get Facebook profiles optimised for community group recommendation threads. Tenterden hospitality and retail get Instagram-first strategies with professional visual content. Rural businesses get Facebook pages configured for village community engagement. Every profile is branded consistently and includes the service information, imagery, and contact details needed to convert a recommendation into an enquiry.',
  '{"population": 133000, "growth": "New estate Facebook groups driving powerful local recommendation culture", "business_districts": ["Ashford Town Centre", "Tenterden High Street", "Chilmington Green", "Finberry", "Rural villages"], "key_fact": "Estate community groups, Tenterden Instagram, and village Facebook pages serve different audience segments"}',
  '[{"title": "Invisible in Ashford Borough estate community group recommendations", "description": "When a Chilmington Green or Finberry resident posts asking for a plumber, electrician, or landscaper, your business cannot be tagged or linked without a properly set up Facebook page. These community groups generate genuine high-intent referrals daily, and businesses without social media profiles are completely excluded from the most powerful word-of-mouth channel in the new estates."}, {"title": "Tenterden businesses with social media that does not match their high street quality", "description": "Tenterden''s independent high street sets a premium visual standard. But many Tenterden businesses have Instagram profiles with inconsistent imagery, sporadic posting, and no coherent visual identity. On a platform where first impressions are entirely visual, a poorly curated Instagram grid undermines the premium positioning that customers expect from a Tenterden business."}, {"title": "Rural businesses missing the village Facebook community conversation", "description": "Villages across Ashford Borough, from Wye to Hamstreet to Charing, have Facebook community pages where residents discuss local services and share recommendations. Businesses without a Facebook presence cannot participate in these conversations, missing the digital equivalent of the village noticeboard that historically drove rural trade recommendations."}]',
  '[{"title": "Estate-group-ready Facebook profiles for Ashford Borough trades", "description": "We build and optimise Facebook business pages specifically for engagement in the new estate community groups. Professional branding, complete service listings, portfolio galleries, and review collection systems ensure that when a Chilmington Green or Finberry resident recommends your business, the profile they find is professional, complete, and converts their interest into a booking."}, {"title": "Premium Instagram setup for Tenterden businesses", "description": "We create Instagram profiles for Tenterden businesses that match the visual standard of the high street. Professional profile optimisation, curated grid layout planning, story highlight organisation, and direct booking link integration. Every element is designed to project the premium quality that Tenterden''s audience expects and that drives actual commercial results."}, {"title": "Village community Facebook presence for rural borough businesses", "description": "For businesses serving the rural areas of Ashford Borough, we set up Facebook pages optimised for village community engagement. Local branding, comprehensive service information, and portfolio content that resonates with the trust-driven purchasing behaviour of rural communities. Your digital presence matches the personal reputation you have built locally."}]',
  '[{"question": "Which social platform matters most for Ashford Borough businesses?", "answer": "It depends entirely on your audience. For trades serving the new estates, Facebook is essential because of the community groups. For Tenterden hospitality and retail, Instagram drives footfall. For rural businesses, Facebook community pages are the primary channel. For B2B services, LinkedIn builds professional credibility. We recommend the platforms that match your specific customer base."}, {"question": "How important are the estate community Facebook groups?", "answer": "Extremely important. Groups for Chilmington Green, Finberry, and Park Farm have thousands of active members who post recommendation requests almost daily. Being tagged in these recommendation threads generates high-quality leads with built-in social proof. A properly set up Facebook business page is the minimum requirement to participate."}, {"question": "Can you set up social media for a Tenterden boutique business?", "answer": "Yes. Tenterden''s boutique businesses need Instagram profiles that project the same quality as their physical premises. We set up profiles with professional imagery guidelines, cohesive grid aesthetics, booking integration, and story templates that maintain the premium visual standard Tenterden customers expect."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup: creating, branding, and optimising your profiles so they are ready to generate business. We provide content templates and posting guides so you can maintain your presence independently. Ongoing management is available as a separate service if you need hands-off social media."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
